        @mcp.tool()
        async def slides_list_files(extension_filter: str | None = None) -> dict:
            """List files already present in the server's ASPOSE_FILES_PATH folder.

            Call this first to discover available files — do NOT ask the user to upload.

            Args:
                extension_filter: Optional file extension to filter by, e.g. 'pptx'. None lists all files.

            Returns:
                dict: {"status": "success"|"error", "files": list[str], "folder_path": str, "message": str}

            Raises:
                None. Errors are returned as {"status": "error", "message": str}.

            Example:
                result = await slides_list_files("pptx")
            """
            import mcp_server.path_utils as _pu  # noqa: PLC0415

            resolved_folder = _pu.FILES_BASE_PATH
            if not resolved_folder or not Path(resolved_folder).is_dir():
                return {"status": "error", "message": "ASPOSE_FILES_PATH folder not found."}

            try:
                files: list[str] = []
                for entry in Path(resolved_folder).iterdir():
                    if not entry.is_file():
                        continue
                    if extension_filter:
                        normalized_ext = f".{extension_filter.lower().lstrip('.')}"
                        if entry.suffix.lower() != normalized_ext:
                            continue
                    files.append(entry.name)
                return {
                    "status": "success",
                    "message": f"Listed {len(files)} file(s).",
                    "files": sorted(files),
                    "folder_path": resolved_folder,
                }
            except Exception as exc:
                logger.exception("Error listing files.")
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def slides_create_presentation(
            output_filename: str,
            title: str | None = None,
            subtitle: str | None = None,
        ) -> dict:
            """Create a new PPTX presentation with an optional title and subtitle.

            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'deck.pptx').

            Args:
                output_filename: Bare filename for the new presentation, e.g. 'new_deck.pptx'.
                title: Optional title text for the first slide.
                subtitle: Optional subtitle text for the first slide.

            Returns:
                dict: {"status": "success"|"error", "message": str, "output_filename": str, "output_path": str}

            Raises:
                Exception: Any unexpected error from Aspose.Slides.

            Example:
                result = await slides_create_presentation("deck.pptx", title="Q1 Review")
            """
            output_filename = Path(output_filename.strip().replace("\x00", "")).name
            resolved_output = get_safe_path(output_filename)
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)

            try:
                import aspose.slides as slides  # noqa: PLC0415

                with slides.Presentation() as pres:
                    slide = pres.slides[0]
                    if title:
                        shape = slide.shapes.add_auto_shape(
                            slides.ShapeType.RECTANGLE, 50, 80, 620, 120
                        )
                        shape.text_frame.text = title
                    if subtitle:
                        shape2 = slide.shapes.add_auto_shape(
                            slides.ShapeType.RECTANGLE, 50, 220, 620, 80
                        )
                        shape2.text_frame.text = subtitle
                    pres.save(str(resolved_output), slides.export.SaveFormat.PPTX)

                return {
                    "status": "success",
                    "message": f"Created presentation: {output_filename}",
                    "output_filename": output_filename,
                    "output_path": str(resolved_output),
                }
            except Exception as exc:
                logger.exception("Failed to create presentation")
                return {"status": "error", "message": str(exc), "output_filename": output_filename}

