        @mcp.tool()
        async def slides_get_presentation_info(input_filename: str) -> dict:
            """Return slide count, title, author, and slide dimensions from a presentation.

            IMPORTANT: All *_filename parameters accept ONLY the bare filename.

            Args:
                input_filename: Bare filename of the presentation to inspect.

            Returns:
                dict: {"status": "success"|"error", "slide_count": int, "title": str,
                       "author": str, "slide_width": float, "slide_height": float, "message": str}

            Raises:
                FileNotFoundError: If the input file does not exist in ASPOSE_FILES_PATH.

            Example:
                result = await slides_get_presentation_info("deck.pptx")
                # result["slide_count"] is an integer
            """
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(
                    f"File not found: {input_filename!r}. "
                    f"Check ASPOSE_FILES_PATH ({platform_hint()})."
                )

            try:
                import aspose.slides as slides  # noqa: PLC0415

                with slides.Presentation(str(resolved_input)) as pres:
                    slide_count = len(pres.slides)
                    props = pres.document_properties
                    title = props.title or ""
                    author = props.author or ""
                    size = pres.slide_size.size
                    slide_width = float(size.width)
                    slide_height = float(size.height)

                return {
                    "status": "success",
                    "message": f"Info for {input_filename}",
                    "slide_count": slide_count,
                    "title": title,
                    "author": author,
                    "slide_width": slide_width,
                    "slide_height": slide_height,
                }
            except Exception as exc:
                logger.exception("Failed to get presentation info")
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def slides_extract_text(input_filename: str) -> dict:
            """Extract all text content from all slides in a presentation.

            Uses SlideUtil.get_all_text_frames for comprehensive extraction.

            IMPORTANT: All *_filename parameters accept ONLY the bare filename.

            Args:
                input_filename: Bare filename of the presentation.

            Returns:
                dict: {"status": "success"|"error", "text": str, "slide_count": int, "message": str}

            Raises:
                FileNotFoundError: If the input file does not exist in ASPOSE_FILES_PATH.

            Example:
                result = await slides_extract_text("deck.pptx")
                # result["text"] contains all extracted text
            """
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(
                    f"File not found: {input_filename!r}. "
                    f"Check ASPOSE_FILES_PATH ({platform_hint()})."
                )

            try:
                import aspose.slides as slides  # noqa: PLC0415
                import aspose.slides.util as util  # noqa: PLC0415

                with slides.Presentation(str(resolved_input)) as pres:
                    slide_count = len(pres.slides)
                    text_frames = util.SlideUtil.get_all_text_frames(pres, True)
                    parts: list[str] = []
                    for tf in text_frames:
                        for para in tf.paragraphs:
                            if para.text.strip():
                                parts.append(para.text)
                    extracted = "\n".join(parts)

                return {
                    "status": "success",
                    "message": f"Extracted text from {slide_count} slide(s).",
                    "slide_count": slide_count,
                    "text": extracted,
                }
            except Exception as exc:
                logger.exception("Failed to extract text")
                return {"status": "error", "message": str(exc)}

