        @mcp.tool()
        async def slides_unprotect_presentation(
            input_filename: str,
            password: str,
            output_filename: str | None = None,
        ) -> dict:
            """Remove the open password from a password-protected presentation.

            Uses aspose.slides.loading.LoadOptions to supply the current password,
            then calls pres.unprotect_presentation().

            IMPORTANT: All *_filename parameters accept ONLY the bare filename.

            Args:
                input_filename: Bare filename of the protected presentation.
                password: Current open password for the presentation.
                output_filename: Bare output filename. Auto-generated if omitted.

            Returns:
                dict: {"status": "success"|"error", "message": str, "output_filename": str, "output_path": str}

            Raises:
                FileNotFoundError: If the input file does not exist in ASPOSE_FILES_PATH.

            Example:
                result = await slides_unprotect_presentation("deck_protected.pptx", "secret")
            """
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(
                    f"File not found: {input_filename!r}. "
                    f"Check ASPOSE_FILES_PATH ({platform_hint()})."
                )

            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
            else:
                stem = Path(input_filename).stem
                output_filename = f"{stem}_unprotected{Path(input_filename).suffix}"
            resolved_output = get_safe_path(output_filename)
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)

            try:
                import aspose.slides as slides  # noqa: PLC0415

                opts = slides.LoadOptions()
                opts.password = password
                with slides.Presentation(str(resolved_input), opts) as pres:
                    pres.protection_manager.remove_encryption()
                    pres.save(str(resolved_output), slides.export.SaveFormat.PPTX)

                return {
                    "status": "success",
                    "message": f"Removed password protection from {input_filename}.",
                    "output_filename": output_filename,
                    "output_path": str(resolved_output),
                }
            except Exception as exc:
                logger.exception("Failed to unprotect presentation")
                return {"status": "error", "message": str(exc), "output_filename": output_filename}

        @mcp.tool()
        async def slides_find_and_replace_text(
            input_filename: str,
            find_text: str,
            replace_text: str,
            output_filename: str | None = None,
        ) -> dict:
            """Replace all occurrences of a text string across all slides.

            Iterates all slides, shapes, text frames, paragraphs, and portions.

            IMPORTANT: All *_filename parameters accept ONLY the bare filename.

            Args:
                input_filename: Bare filename of the source presentation.
                find_text: Text to search for.
                replace_text: Replacement text.
                output_filename: Bare output filename. Auto-generated if omitted.

            Returns:
                dict: {"status": "success"|"error", "message": str, "output_filename": str,
                       "output_path": str, "replacements": int}

            Raises:
                FileNotFoundError: If the input file does not exist in ASPOSE_FILES_PATH.

            Example:
                result = await slides_find_and_replace_text("deck.pptx", "{{NAME}}", "Shahzad")
            """
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(
                    f"File not found: {input_filename!r}. "
                    f"Check ASPOSE_FILES_PATH ({platform_hint()})."
                )

            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
            else:
                stem = Path(input_filename).stem
                output_filename = f"{stem}_replaced{Path(input_filename).suffix}"
            resolved_output = get_safe_path(output_filename)
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)

            try:
                import aspose.slides as slides  # noqa: PLC0415

                replacements = 0
                with slides.Presentation(str(resolved_input)) as pres:
                    for slide in pres.slides:
                        for shape in slide.shapes:
                            try:
                                tf = shape.text_frame
                            except AttributeError:
                                continue
                            for para in tf.paragraphs:
                                for portion in para.portions:
                                    if find_text in portion.text:
                                        count = portion.text.count(find_text)
                                        portion.text = portion.text.replace(find_text, replace_text)
                                        replacements += count
                    pres.save(str(resolved_output), slides.export.SaveFormat.PPTX)

                return {
                    "status": "success",
                    "message": f"Replaced {replacements} occurrence(s) of {find_text!r}.",
                    "output_filename": output_filename,
                    "output_path": str(resolved_output),
                    "replacements": replacements,
                }
            except FileNotFoundError:
                raise
            except Exception as exc:
                logger.exception("Failed to find and replace text")
                return {"status": "error", "message": str(exc), "output_filename": output_filename}

        @mcp.tool()
        async def slides_reorder_slide(
            input_filename: str,
            from_index: int,
            to_index: int,
            output_filename: str | None = None,
        ) -> dict:
            """Move a slide from one position to another (both indices are 0-based).

            Uses pres.slides.reorder(to_index, pres.slides[from_index]).
            Slide indexing is 0-based: from_index=0 is the first slide.

            IMPORTANT: All *_filename parameters accept ONLY the bare filename.

            Args:
                input_filename: Bare filename of the source presentation.
                from_index: 0-based current position of the slide to move.
                to_index: 0-based target position for the slide.
                output_filename: Bare output filename. Auto-generated if omitted.

            Returns:
                dict: {"status": "success"|"error", "message": str, "output_filename": str, "output_path": str}

            Raises:
                FileNotFoundError: If the input file does not exist in ASPOSE_FILES_PATH.

            Example:
                result = await slides_reorder_slide("deck.pptx", 2, 0, "deck_reordered.pptx")
            """
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(
                    f"File not found: {input_filename!r}. "
                    f"Check ASPOSE_FILES_PATH ({platform_hint()})."
                )

            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
            else:
                stem = Path(input_filename).stem
                output_filename = f"{stem}_reordered{Path(input_filename).suffix}"
            resolved_output = get_safe_path(output_filename)
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)

            try:
                import aspose.slides as slides  # noqa: PLC0415

                with slides.Presentation(str(resolved_input)) as pres:
                    slide_count = len(pres.slides)
                    if from_index < 0 or from_index >= slide_count:
                        raise IndexError(
                            f"from_index {from_index} out of range for "
                            f"{slide_count} slide(s)."
                        )
                    if to_index < 0 or to_index >= slide_count:
                        raise IndexError(
                            f"to_index {to_index} out of range for "
                            f"{slide_count} slide(s)."
                        )
                    pres.slides.reorder(to_index, pres.slides[from_index])
                    pres.save(str(resolved_output), slides.export.SaveFormat.PPTX)

                return {
                    "status": "success",
                    "message": f"Moved slide {from_index} → position {to_index}.",
                    "output_filename": output_filename,
                    "output_path": str(resolved_output),
                }
            except (FileNotFoundError, IndexError):
                raise
            except Exception as exc:
                logger.exception("Failed to reorder slide")
                return {"status": "error", "message": str(exc), "output_filename": output_filename}
